                  </div>}
                >
                  <Title level={5} style={{ margin: '5px 0' }}>{food.foodName}</Title>
                  <Text type="secondary" style={{ display: 'block', marginBottom: 10 }}>{food.unitPrice.toLocaleString('vi-VN')} đ</Text>

                  <Button 
                    type="primary" shape="round" className="btn-primary-custom" style={{ width: '80%' }} 
                    onClick={() => openFoodDetail(food)}
                    disabled={!food.available}
                  >
                    {food.available ? 'Thêm' : 'Hết món'}
                  </Button>
                </Card>
              </Col>
            ))
          )}
        </Row>
      </div>

      {/* ================= MODAL 1: CHI TIẾT MÓN ĂN ================= */}
      <Modal open={!!selectedFood} onCancel={closeFoodDetail} footer={null} closeIcon={<CloseOutlined style={{ fontSize: 20 }} />} bodyStyle={{ padding: 0 }} width={400}>
        {selectedFood && (
          <div>
            <img src={selectedFood.imageUrlFood} alt={selectedFood.foodName} style={{ width: '100%', height: 250, objectFit: 'cover', borderRadius: '8px 8px 0 0' }} />
            <div style={{ padding: 20 }}>
              <Title level={4} style={{ margin: 0 }}>{selectedFood.foodName}</Title>
              <Text type="secondary">{selectedFood.description}</Text>

              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 30 }}>
                <Space size="middle">
                  <Button shape="circle" icon={<MinusOutlined />} onClick={() => setFoodQuantity(Math.max(1, foodQuantity - 1))} />
                  <Text strong style={{ fontSize: 18 }}>{foodQuantity}</Text>
                  <Button shape="circle" icon={<PlusOutlined />} onClick={() => setFoodQuantity(foodQuantity + 1)} />
                </Space>

                <Button type="primary" shape="round" size="large" className="btn-primary-custom" onClick={handleAddToCart}>
                  Thêm vào giỏ ({(selectedFood.unitPrice * foodQuantity).toLocaleString('vi-VN')} đ)
                </Button>
              </div>
            </div>
          </div>
        )}
      </Modal>

      {/* ================= MODAL 2: GIỎ HÀNG ================= */}
      <Modal title={<Title level={4} style={{ textAlign: 'center', margin: 0 }}>GIỎ HÀNG</Title>} open={isCartModalOpen} onCancel={() => setIsCartModalOpen(false)} footer={null} closeIcon={<CloseOutlined style={{ fontSize: 20 }} />} width={450} bodyStyle={{ background: '#f5f5f5', padding: 10, maxHeight: '60vh', overflowY: 'auto' }}>
        <List
          dataSource={cart}
          renderItem={item => (
            <Card size="small" style={{ marginBottom: 10, borderRadius: 8 }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <img src={item.imageUrlFood} alt={item.foodName} style={{ width: 60, height: 60, objectFit: 'cover', borderRadius: 4, marginRight: 10 }} />
                <div style={{ flex: 1 }}>
                  <Text strong>{item.foodName}</Text><br/>
                  <Text type="secondary">{item.unitPrice.toLocaleString('vi-VN')} đ</Text>
                </div>
                <Space>
                  <Button size="small" icon={<MinusOutlined />} onClick={() => updateCartQuantity(item.idFood, -1)} />
                  <Text>{item.quantity}</Text>
                  <Button size="small" icon={<PlusOutlined />} onClick={() => updateCartQuantity(item.idFood, 1)} />
                  <Button size="small" type="text" danger onClick={() => removeFromCart(item.idFood)}>Xóa</Button>
                </Space>
              </div>
            </Card>
          )}
        />

        <div style={{ background: '#fff', padding: 15, borderRadius: 8, marginTop: 10, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Title level={4} type="danger" style={{ margin: 0 }}>Tổng: {calculateTotal().toLocaleString('vi-VN')} đ</Title>
          <Button type="primary" size="large" shape="round" className="btn-primary-custom" onClick={handlePlaceOrder}>
            Đặt món
          </Button>
        </div>
      </Modal>

    </div>
  );
};

export default FoodMenu;

import React, { useEffect, useMemo, useState } from 'react';
import { Input, Button, Empty, Spin, message } from 'antd';
import { SearchOutlined, DownOutlined, UpOutlined, MinusSquareOutlined } from '@ant-design/icons';
import apiClient from '../api/apiClient';
import '../css/KitchenPage.css';

const DEFAULT_FOOD_IMAGE = 'https://via.placeholder.com/120x120?text=FOOD';

const formatElapsed = (minutes) => {
  const safeMinutes = Number.isFinite(minutes) ? Math.max(minutes, 0) : 0;
  const hour = String(Math.floor(safeMinutes / 60)).padStart(2, '0');
  const minute = String(safeMinutes % 60).padStart(2, '0');
  return `${hour}h:${minute}m`;
};

const KitchenPage = () => {
  const [activeTab, setActiveTab] = useState('orders');
  const [searchText, setSearchText] = useState('');
  const [tableOrders, setTableOrders] = useState([]);
  const [remainingFoods, setRemainingFoods] = useState([]);
  const [expandedMap, setExpandedMap] = useState({});
  const [loading, setLoading] = useState(true);
  const [servingIds, setServingIds] = useState([]);

  const fetchKitchenData = async () => {
    try {
      setLoading(true);
      const [ordersRes, foodsRes] = await Promise.all([
        apiClient.get('/v1/kitchen/orders'),
        apiClient.get('/v1/kitchen/foods/remaining')
      ]);

      const orders = ordersRes?.data?.data ?? [];
      const foods = foodsRes?.data?.data ?? [];

      setTableOrders(orders);
      setRemainingFoods(foods);
      setExpandedMap((prev) => {
        const next = { ...prev };
        orders.forEach((table) => {
          if (next[table.tableNumber] === undefined) {
            next[table.tableNumber] = true;
          }
        });
        return next;
      });
    } catch (error) {
      console.error(error);
      message.error('Khong tai duoc du lieu nha bep');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchKitchenData();
  }, []);

  const onServeItem = async (orderDetailId) => {
    try {
      setServingIds((prev) => [...prev, orderDetailId]);
      await apiClient.post(`/v1/kitchen/orders/items/${orderDetailId}/served`);
      message.success('Da cap nhat mon da hoan thanh');
      await fetchKitchenData();
    } catch (error) {
      console.error(error);
      const errorMessage = error?.response?.data?.message || 'Cap nhat mon that bai';
      message.error(errorMessage);
    } finally {
      setServingIds((prev) => prev.filter((id) => id !== orderDetailId));
    }
  };

  const filteredTableOrders = useMemo(() => {
    const normalized = searchText.trim().toLowerCase();
    if (!normalized) {
      return tableOrders;
    }

    return tableOrders
      .map((table) => {
        const matchedItems = table.items.filter((item) =>
          item.foodName?.toLowerCase().includes(normalized)
        );
        const matchedTable = table.tableNumber?.toLowerCase().includes(normalized);

        if (matchedTable) {
          return table;
        }

        return { ...table, items: matchedItems };
      })
      .filter((table) => table.items.length > 0 || table.tableNumber?.toLowerCase().includes(normalized));
  }, [searchText, tableOrders]);

  const filteredRemainingFoods = useMemo(() => {
    const normalized = searchText.trim().toLowerCase();
    if (!normalized) {
      return remainingFoods;
    }

    return remainingFoods.filter((food) =>
      food.foodName?.toLowerCase().includes(normalized)
    );
  }, [searchText, remainingFoods]);

  const headerTitle = activeTab === 'orders' ? 'Don hang' : 'Mon an';

  return (
    <div className="kitchen-page">
      <aside className="kitchen-sidebar">
        <div className="kitchen-logo">LOGO</div>

        <Button
          className={`kitchen-tab-btn ${activeTab === 'orders' ? 'active' : ''}`}
          onClick={() => setActiveTab('orders')}
        >
          Don hang
        </Button>
        <Button
          className={`kitchen-tab-btn ${activeTab === 'foods' ? 'active' : ''}`}
          onClick={() => setActiveTab('foods')}
        >
          Danh sach mon
        </Button>
      </aside>

      <section className="kitchen-main">
        <div className="kitchen-topbar">
          <h3>{headerTitle}</h3>
          <Input
            prefix={<SearchOutlined />}
            value={searchText}
            onChange={(event) => setSearchText(event.target.value)}
            placeholder="search"
            className="kitchen-search"
          />
        </div>

        <div className="kitchen-content">
          {loading ? (
            <div className="kitchen-loading">
              <Spin size="large" />
            </div>
          ) : activeTab === 'orders' ? (
            filteredTableOrders.length === 0 ? (
              <Empty description="Khong co don hang dang cho" />
            ) : (
              filteredTableOrders.map((table) => {
                const expanded = expandedMap[table.tableNumber] !== false;

                return (
                  <div className="table-card" key={table.tableNumber}>
                    <div className="table-card-header">
                      <span>
                        Ban: {table.tableNumber} - {formatElapsed(table.elapsedMinutes)}
                      </span>
                      <button
                        type="button"
                        className="toggle-btn"
                        onClick={() =>
                          setExpandedMap((prev) => ({
                            ...prev,
                            [table.tableNumber]: !expanded
                          }))
                        }
                      >
                        {expanded ? (
                          <>
                            An bot <UpOutlined />
                          </>
                        ) : (
                          <>
                            Hien them <DownOutlined />
                          </>
                        )}
                      </button>
                    </div>

                    {expanded && (
                      <div className="table-card-body">
                        {table.items.map((item) => (
                          <div className="kitchen-item" key={item.orderDetailId}>
                            <img
                              src={item.imageUrlFood || DEFAULT_FOOD_IMAGE}
                              alt={item.foodName}
                              className="item-image"
                              onError={(event) => {
                                event.currentTarget.src = DEFAULT_FOOD_IMAGE;
                              }}
                            />
                            <div className="item-info">
                              <p className="item-title">{item.foodName}</p>
                              <p className="item-qty">So luong: {item.quantity}</p>
                            </div>
                            <Button
                              type="text"
                              icon={<MinusSquareOutlined />}
                              className="done-btn"
                              onClick={() => onServeItem(item.orderDetailId)}
                              loading={servingIds.includes(item.orderDetailId)}
                            />
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                );
              })
            )
          ) : filteredRemainingFoods.length === 0 ? (
            <Empty description="Khong co mon con lai" />
          ) : (
            <div className="food-list-card">
              {filteredRemainingFoods.map((food) => (
                <div className="kitchen-item" key={food.foodId}>
                  <img
                    src={food.imageUrlFood || DEFAULT_FOOD_IMAGE}
                    alt={food.foodName}
                    className="item-image"
                    onError={(event) => {
                      event.currentTarget.src = DEFAULT_FOOD_IMAGE;
                    }}
                  />
                  <div className="item-info">
                    <p className="item-title">{food.foodName}</p>
                    <p className="item-qty">So luong con lai: {food.remainingQuantity}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default KitchenPage;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import apiClient from '../api/apiClient.js'; // Đảm bảo đường dẫn này đúng với project của bạn
import './Login.css'; // Import file giao diện vừa tạo ở trên

const Login = () => {
    // 1. Tạo các state để lưu dữ liệu người dùng gõ vào
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const navigate = useNavigate();

    // 2. Hàm xử lý khi bấm nút Đăng nhập
    const handleLogin = async (e) => {
        e.preventDefault(); // Chặn việc tự động reload trang của thẻ form
        setError('');
        setLoading(true); // Hiển thị trạng thái đang load

        try {
            // Gửi API lên Spring Boot
            const response = await apiClient.post('/auth/login', { username, password });

            // Lấy vai trò (role) từ Backend trả về
            const userRole = response.data.role;

            // Điều hướng màn hình tùy theo Role
            if (userRole === 'Admin' || userRole === 'Quản lý') {
                navigate('/inventory'); // Quản lý cho vào trang Kho
            } else if (userRole === 'Bếp') {
                navigate('/kitchen');
            } else if (userRole === 'Thu ngân') {
                navigate('/pos');
            } else {
                navigate('/');
            }
        } catch (err) {
            // Nếu Spring Boot trả về lỗi 401 (Sai tài khoản/Mật khẩu)
            setError('Sai tài khoản hoặc mật khẩu!');
        } finally {
            setLoading(false); // Tắt trạng thái load
        }
    };

    // 3. Phần giao diện (JSX)
    return (
        <div className="page-container">
            {/* Thanh bên (Sidebar) màu xám bên trái */}
            <div className="sidebar">
                <div className="logo">LOGO</div>
                <div className="slogan-box">
                    <p className="large-gap">Slogan và 1 số ảnh liên quan</p>
                    <p>ăn nhanh chết sớm</p>
                </div>
            </div>

            {/* Nội dung chính màu trắng bên phải */}
            <div className="main-content">
                <p className="instruction-text">Ảnh nền chủ đề đồ ăn</p>
                <div className="login-card">
                    <h2>Đăng nhập vào hệ thống</h2>

                    {/* Gắn hàm handleLogin vào sự kiện submit của form */}
                    <form onSubmit={handleLogin}>
                        <div className="input-group">
                            <label htmlFor="username">Tài khoản</label>
                            <input
                                type="text"
                                id="username"
                                placeholder="Tên tài khoản"
                                value={username}
                                onChange={(e) => setUsername(e.target.value)} // Lưu chữ khách gõ vào state
                                required
                            />
                        </div>
                        <div className="input-group">
                            <label htmlFor="password">Mật khẩu</label>
                            <input
                                type="password"
                                id="password"
                                placeholder="Nhập mật khẩu"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)} // Lưu pass khách gõ vào state
                                required
                            />
                        </div>

                        {/* Hiện thông báo chữ màu đỏ nếu nhập sai mật khẩu */}
                        {error && <p style={{ color: 'red', textAlign: 'center', marginBottom: '15px' }}>{error}</p>}

                        <button type="submit" className="login-button" disabled={loading}>
                            {loading ? 'Đang xử lý...' : 'Đăng nhập'}
                        </button>
                    </form>
                </div>
            </div>
        </div>
    );
};

export default Login;

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import apiClient from '../api/apiClient.js'; // Đảm bảo đường dẫn này đúng với project của bạn
import './Login.css'; // Import file giao diện vừa tạo ở trên

const normalizeRole = (role) => {
    const normalized = (role || '').trim().toLowerCase();

    if (normalized === 'admin') return 'ADMIN';
    if (normalized === 'thu ngân' || normalized === 'thu ngan') return 'Thu ngân';
    if (normalized === 'bếp' || normalized === 'bep') return 'Bếp';
    if (normalized === 'khách hàng' || normalized === 'khach hang') return 'Khách hàng';

    return role || '';
};

const getRoleHomePath = (role) => {
    const normalizedRole = normalizeRole(role);

    if (normalizedRole === 'ADMIN') return '/dashboard';
    if (normalizedRole === 'Thu ngân') return '/payment';
    if (normalizedRole === 'Bếp') return '/kitchen';
    if (normalizedRole === 'Khách hàng') return '/menu';

    return '/login';
};

const isRoleNavigable = (role) => getRoleHomePath(role) !== '/login';

const Login = () => {
    // 1. Tạo các state để lưu dữ liệu người dùng gõ vào
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const navigate = useNavigate();

    useEffect(() => {
        const savedRole = localStorage.getItem('userRole');
        if (savedRole && isRoleNavigable(savedRole)) {
            navigate(getRoleHomePath(savedRole), { replace: true });
        }
    }, [navigate]);

    // 2. Hàm xử lý khi bấm nút Đăng nhập
    const handleLogin = async (e) => {
        e.preventDefault(); // Chặn việc tự động reload trang của thẻ form
        setError('');
        setLoading(true); // Hiển thị trạng thái đang load

        try {
            // Gửi API lên Spring Boot
            const response = await apiClient.post('/auth/login', { username, password });

            // Lấy vai trò (role) từ Backend trả về
            const userRole = normalizeRole(response.data.role);

            localStorage.setItem('userRole', userRole);
            localStorage.setItem('username', response.data.username || '');
            localStorage.setItem('fullName', response.data.fullName || '');

            const source = `${response.data.fullName || ''} ${response.data.username || ''}`;
            const tableMatch = source.match(/([A-Z]\d{2})/i);
            if (tableMatch?.[1]) {
                localStorage.setItem('tableNumber', `Bàn ${tableMatch[1].toUpperCase()}`);
            } else {
                localStorage.removeItem('tableNumber');
            }

            navigate(getRoleHomePath(userRole), { replace: true });
        } catch (err) {
            // Nếu Spring Boot trả về lỗi 401 (Sai tài khoản/Mật khẩu)
            setError(err?.response?.data || 'Sai tài khoản hoặc mật khẩu!');
        } finally {
            setLoading(false); // Tắt trạng thái load
        }
    };

    // 3. Phần giao diện (JSX)
    return (
        <div className="page-container">
            {/* Thanh bên (Sidebar) màu xám bên trái */}
            <div className="sidebar">
                <div className="logo">LOGO</div>
                <div className="slogan-box">
                    <p className="large-gap">Slogan và 1 số ảnh liên quan</p>
                    <p>ăn nhanh chết sớm</p>
                </div>
            </div>

            {/* Nội dung chính màu trắng bên phải */}
            <div className="main-content">
                <p className="instruction-text">Ảnh nền chủ đề đồ ăn</p>
                <div className="login-card">
                    <h2>Đăng nhập vào hệ thống</h2>

                    {/* Gắn hàm handleLogin vào sự kiện submit của form */}
                    <form onSubmit={handleLogin}>
                        <div className="input-group">
                            <label htmlFor="username">Tài khoản</label>
                            <input
                                type="text"
                                id="username"
                                placeholder="Tên tài khoản"
                                value={username}
                                onChange={(e) => setUsername(e.target.value)} // Lưu chữ khách gõ vào state
                                required
                            />
                        </div>
                        <div className="input-group">
                            <label htmlFor="password">Mật khẩu</label>
                            <input
                                type="password"
                                id="password"
                                placeholder="Nhập mật khẩu"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)} // Lưu pass khách gõ vào state
                                required
                            />
                        </div>

                        {/* Hiện thông báo chữ màu đỏ nếu nhập sai mật khẩu */}
                        {error && <p style={{ color: 'red', textAlign: 'center', marginBottom: '15px' }}>{error}</p>}

                        <button type="submit" className="login-button" disabled={loading}>
                            {loading ? 'Đang xử lý...' : 'Đăng nhập'}
                        </button>
                    </form>
                </div>
            </div>
        </div>
    );
};

export default Login;

